import React from 'react';
import { NavLink } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';

const BookingTabs = () => {
  const { isAdmin } = useAuth();
  const adminView = isAdmin?.() === true;

  return (
    <nav className="booking-tabs" aria-label="Bookings navigation">
      <NavLink
        to="/bookings"
        end
        className={({ isActive }) => `booking-tab ${isActive ? 'active' : ''}`}
      >
        Bookings
      </NavLink>

      <NavLink
        to="/bookings/new"
        className={({ isActive }) => `booking-tab ${isActive ? 'active' : ''}`}
      >
        New Booking
      </NavLink>

      <NavLink
        to="/bookings/calendar"
        className={({ isActive }) => `booking-tab ${isActive ? 'active' : ''}`}
      >
        Calendar
      </NavLink>

      {adminView ? (
        <NavLink
          to="/admin/bookings"
          className={({ isActive }) => `booking-tab ${isActive ? 'active' : ''}`}
        >
          Requests
        </NavLink>
      ) : (
        <span className="booking-tab disabled" aria-disabled="true">
          Requests
        </span>
      )}
    </nav>
  );
};

export default BookingTabs;
